patch:
--- a/multiplexer.v
+++ b/multiplexer.v
@@ -1,6 +1,6 @@
 module multiplexer_4to1(
   input [7:0] data_a, data_b, data_c, data_d,
   input [1:0] sel,
   output reg [7:0] mux_out
 );
-  always @(data_a or data_b or sel) begin
+  always @(data_a or data_b or data_c or data_d or sel) begin
     case(sel)
       2'b00: mux_out = data_a;
       2'b01: mux_out = data_b;

before_code:
module multiplexer_4to1(
  input [7:0] data_a, data_b, data_c, data_d,
  input [1:0] sel,
  output reg [7:0] mux_out
);
  always @(data_a or data_b or sel) begin
    case(sel)
      2'b00: mux_out = data_a;
      2'b01: mux_out = data_b;
      2'b10: mux_out = data_c;
      2'b11: mux_out = data_d;
    endcase
  end
endmodule

after_code:
module multiplexer_4to1(
  input [7:0] data_a, data_b, data_c, data_d,
  input [1:0] sel,
  output reg [7:0] mux_out
);
  always @(data_a or data_b or data_c or data_d or sel) begin
    case(sel)
      2'b00: mux_out = data_a;
      2'b01: mux_out = data_b;
      2'b10: mux_out = data_c;
      2'b11: mux_out = data_d;
    endcase
  end
endmodule
